import json
with open('baseline-packages.json') as f: b = json.load(f)
with open('after-cpm-packages.json') as f: a = json.load(f)
def extract(data):
    result = {}
    for p in data['projects']:
        name = p['path'].split('/')[-2]
        for fw in p['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                result[(name, pkg['id'])] = pkg['resolvedVersion']
    return result
bp, ap = extract(b), extract(a)
if bp == ap: print('Package versions are identical before and after conversion.')
else:
    for k in bp.keys() | ap.keys():
        if bp.get(k) != ap.get(k): print(f'CHANGED: {k}: {bp.get(k)} -> {ap.get(k)}')
"

